/** Clickable penalty/adjustment icon with popover details */
function PenaltyIndicator({
	result,
}: {
	result: CompetitionLeaderboardEntry["eventResults"][number]
}) {
	if (!result.penaltyType && !result.isDirectlyModified) return null

	if (result.isDirectlyModified) {
		return (
			<Popover>
				<PopoverTrigger asChild>
					<button
						type="button"
						className="inline-flex items-center text-blue-500 hover:text-blue-600"
						aria-label="Score adjusted"
					>
						<Pencil className="h-3 w-3" />
					</button>
				</PopoverTrigger>
				<PopoverContent className="w-auto max-w-[200px] p-3">
					<p className="text-sm font-medium">Score Adjusted</p>
					<p className="text-xs text-muted-foreground mt-1">
						This score was modified by an organizer.
					</p>
				</PopoverContent>
			</Popover>
		)
	}

	const isMajor = result.penaltyType === "major"

	return (
		<Popover>
			<PopoverTrigger asChild>
				<button
					type="button"
					className={cn(
						"inline-flex items-center hover:opacity-80",
						isMajor ? "text-red-500" : "text-amber-500",
					)}
					aria-label={`${isMajor ? "Major" : "Minor"} penalty applied`}
				>
					<AlertTriangle className="h-3 w-3" />
				</button>
			</PopoverTrigger>
			<PopoverContent className="w-auto max-w-[220px] p-3">
				<p
					className={cn(
						"text-sm font-medium",
						isMajor ? "text-red-600" : "text-amber-600",
					)}
				>
					{isMajor ? "Major" : "Minor"} Penalty
				</p>
				{result.penaltyPercentage != null && (
					<p className="text-xs text-muted-foreground mt-1">
						{result.penaltyPercentage}% deduction applied
					</p>
				)}
			</PopoverContent>
		</Popover>
	)
}

